int hasCycle(Node *head) {
    Node *slow = head;
    Node *fast = head;

    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast)
            return 1;  /* cycle detected */
    }
    return 0;  /* no cycle */
}

/* Find the starting node of the cycle, or NULL if no cycle */
Node *findCycleStart(Node *head) {
    Node *slow = head;
    Node *fast = head;

    /* Phase 1: Detect cycle */
    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast)
            break;
    }

    /* No cycle */
    if (fast == NULL || fast->next == NULL)
        return NULL;

    /* Phase 2: Find start of cycle */
    slow = head;
    while (slow != fast) {
        slow = slow->next;
        fast = fast->next;  /* both move 1 step now */
    }
    return slow;  /* start of cycle */
}

