/* Merge two sorted lists into one sorted list (iterative) */
Node *mergeSorted(Node *l1, Node *l2) {
    Node dummy;          /* stack-allocated sentinel */
    dummy.next = NULL;
    Node *tail = &dummy;

    while (l1 != NULL && l2 != NULL) {
        if (l1->data <= l2->data) {
            tail->next = l1;
            l1 = l1->next;
        } else {
            tail->next = l2;
            l2 = l2->next;
        }
        tail = tail->next;
    }

    /* Attach remaining nodes */
    tail->next = (l1 != NULL) ? l1 : l2;

    return dummy.next;
}

/* Recursive merge */
Node *mergeSortedRecursive(Node *l1, Node *l2) {
    if (l1 == NULL) return l2;
    if (l2 == NULL) return l1;

    if (l1->data <= l2->data) {
        l1->next = mergeSortedRecursive(l1->next, l2);
        return l1;
    } else {
        l2->next = mergeSortedRecursive(l1, l2->next);
        return l2;
    }
}

