}

/* Find nth node from end (1-indexed: n=1 means last node) */
Node *nthFromEnd(Node *head, int n) {
    Node *first = head;
    Node *second = head;

    /* Move first n steps ahead */
    for (int i = 0; i < n; i++) {
        if (first == NULL) return NULL;  /* n > list length */
        first = first->next;
    }

    /* Move both until first reaches NULL */
    while (first != NULL) {
        first = first->next;
        second = second->next;
    }

    return second;
}

