    result = nthFromEnd(head, 5);  /* 5th from end = head */
    if (result)
        printf("5th from end: %d\n", result->data);  /* 10 */

    result = nthFromEnd(head, 6);  /* beyond list */
    printf("6th from end: %s\n", result ? "found" : "NULL");  /* NULL */

    return 0;
}

Node *nthFromEnd(Node *head, int n) {
    Node *first = head, *second = head;
    for (int i = 0; i < n; i++) {
        if (!first) return NULL;
        first = first->next;
    }
    while (first) {
        first = first->next;
        second = second->next;
    }
    return second;
}

