int getLength(Node *head) {
    int len = 0;
    while (head) { len++; head = head->next; }
    return len;
}

/* Approach 1: Length difference */
Node *getIntersection(Node *headA, Node *headB) {
    int lenA = getLength(headA);
    int lenB = getLength(headB);

    /* Advance the longer list */
    while (lenA > lenB) { headA = headA->next; lenA--; }
    while (lenB > lenA) { headB = headB->next; lenB--; }

    /* Move both until they meet */
    while (headA != headB) {
        headA = headA->next;
        headB = headB->next;
    }
    return headA;  /* NULL if no intersection */
}

/* Approach 2: Two-pointer redirect trick */
Node *getIntersectionV2(Node *headA, Node *headB) {
    Node *a = headA;
    Node *b = headB;

    while (a != b) {
        a = (a != NULL) ? a->next : headB;
        b = (b != NULL) ? b->next : headA;
    }
    return a;  /* intersection node or NULL */
}

int main(void) {
