#include <stdio.h>
#include <stdlib.h>

typedef struct RNode {
    int data;
    struct RNode *next;
    struct RNode *random;
} RNode;

RNode *createRNode(int val) {
    RNode *n = (RNode *)malloc(sizeof(RNode));
    n->data = val;
    n->next = NULL;
    n->random = NULL;
    return n;
}

/* Clone using interleaving: O(n) time, O(1) extra space */
RNode *cloneList(RNode *head) {
    if (head == NULL) return NULL;

    /* Step 1: Insert copy after each original node */
    RNode *curr = head;
    while (curr != NULL) {
        RNode *copy = createRNode(curr->data);
        copy->next = curr->next;
        curr->next = copy;
        curr = copy->next;
    }

    /* Step 2: Set random pointers for copies */
    curr = head;
    while (curr != NULL) {
        RNode *copy = curr->next;
        copy->random = (curr->random != NULL) ? curr->random->next : NULL;
        curr = copy->next;
    }

    /* Step 3: Separate the two interleaved lists */
    RNode *cloneHead = head->next;
    curr = head;
    while (curr != NULL) {
        RNode *copy = curr->next;
        curr->next = copy->next;
        copy->next = (copy->next != NULL) ? copy->next->next : NULL;
        curr = curr->next;
    }

    return cloneHead;
}

void printRList(RNode *head) {
    while (head) {
        printf("[%d, random->%s] -> ", head->data,
               head->random ? (char[12]){0} : "NULL");
        if (head->random) printf("(%d) ", head->random->data);
        head = head->next;
    }
    printf("NULL\n");
}

int main(void) {
    RNode *n1 = createRNode(1);
    RNode *n2 = createRNode(2);
    RNode *n3 = createRNode(3);
    n1->next = n2; n2->next = n3;
    n1->random = n3;  /* 1's random -> 3 */
    n2->random = n1;  /* 2's random -> 1 */
    n3->random = n2;  /* 3's random -> 2 */

    RNode *clone = cloneList(n1);

    /* Verify clone is independent */
    printf("Original: %d, Clone: %d\n", n1->data, clone->data);
    printf("Same memory? %s\n", (n1 == clone) ? "YES" : "NO");  /* NO */
    printf("Clone random: %d\n", clone->random->data);  /* 3 */
    printf("Clone->next->random: %d\n", clone->next->random->data);  /* 1 */

    return 0;
}

typedef struct RNode {
    int data;
    struct RNode *next;
    struct RNode *random;
} RNode;

RNode *cloneList(RNode *head) {
    if (!head) return NULL;
    /* Step 1: Interleave copies */
    for (RNode *c = head; c; c = c->next->next) {
        RNode *cp = createRNode(c->data);
        cp->next = c->next; c->next = cp;
    }
    /* Step 2: Set random pointers */
    for (RNode *c = head; c; c = c->next->next)
        c->next->random = c->random ? c->random->next : NULL;
    /* Step 3: Separate */
    RNode *clone = head->next;
    for (RNode *c = head; c; c = c->next) {
        RNode *cp = c->next;
        c->next = cp->next;
        cp->next = cp->next ? cp->next->next : NULL;
    }
    return clone;
}

